mapper.update:
UPDATE UB_SURVEY us
SET us.survey_approval = 'T'
WHERE us.member_number = #{memberNumber}

UPDATE UB_MEMBER um
SET um.member_type = (
	SELECT survey_type
	FROM UB_SURVEY us
	WHERE us.member_number = #{memberNumber}
)
WHERE um.member_number= #{memberNumber}

UPDATE UB_SURVEY us
SET us.survey_approval = 'F'
  , us.survey_rej_reason = #{rejectReason}
WHERE us.member_number = #{memberNumber}
